span.style:
font-size: 11px;
font-weight: 700;
letter-spacing: 0.05em;
color: var(--ac);
background: rgba(157,229,255,0.10);
border: 1px solid rgba(157,229,255,0.35);
border-radius: 6px;
padding: 2px 7px;
margin-left: 10px;
vertical-align: middle;
line-height: 1.4;
font-family: var(--mono);
position: relative;
top: -16px;
margin-left: -3px;

div.style:
display:none;
position:absolute;
pointer-events:none;
z-index:50;
outline:2px solid var(--ac,#9de5ff);
outline-offset:0px;
box-shadow:0 0 0 4px rgba(157,229,255,0.18), inset 0 0 0 9999px rgba(157,229,255,0.08);
border-radius:2px;
transition:top .08s,left .08s,width .08s,height .08s;

position:absolute;
width:380px;
background:var(--bg2);
border:1px solid var(--ac);
border-radius:16px;
padding:24px 26px 20px;
box-shadow:0 12px 50px rgba(0,0,0,0.7), 0 0 0 1px rgba(100,210,255,0.08);
pointer-events:all;
transition: opacity .25s, transform .25s;
opacity:0;
transform:translateY(8px);
z-index:10;
